/** Resolve a stored media_path key → [startFrame, endFrame] module refs, or null. */
export function resolveExerciseMedia(key: string | null | undefined): MediaPair | null {
  if (!key) return null;
  return EXERCISE_MEDIA[key] ?? null;
}
